css:
@page { size: 240mm 105mm; margin: 4mm 0 4mm 0; }
.print-format { page-width: 240mm; page-height: 105mm; orientation: Landscape; margin: 0 !important; margin-left: 0.1mm !important; margin-right: 0.1mm !important; margin-top: 0.1mm !important; margin-bottom: 0.1mm !important; padding: 0 !important; width: 240mm; height: 78mm; min-height: 0 !important; max-height: 78mm; overflow-x: visible !important; overflow-y: hidden !important; page-break-after: avoid !important; break-after: avoid-page !important; }
html, body { width: 240mm; height: 78mm; max-height: 78mm; margin: 0 !important; padding: 0 !important; overflow-x: visible !important; overflow-y: hidden !important; }
body { font-family: Arial, Helvetica, sans-serif; color: #111; }
.action-banner, .print-hide { display: none !important; }
.print-format-gutter { margin: 0 !important; padding: 0 !important; width: 240mm; height: 78mm; max-height: 78mm; overflow-x: visible !important; overflow-y: hidden !important; }
.ts { position: relative; width: 100%; height: 78mm; min-height: 0; max-height: 78mm; overflow-x: visible; overflow-y: hidden; box-sizing: border-box; padding: 15mm 30mm 0 15mm; page-break-inside: avoid; break-inside: avoid; }
.ts-row { display: flex; justify-content: space-between; align-items: flex-start; gap: 4mm; }
.ts-main { flex: 1; min-width: 0; }
.ts-name { font-size: 20pt; font-weight: 700; line-height: 1.05; margin: 0 0 1.5mm 0; overflow-wrap: anywhere; }
.ts-wohnung-id { display: inline-block; box-sizing: border-box; min-width: 9mm; height: 9mm; line-height: 8mm; padding: 0 1.5mm; border: 0.7pt solid #444; border-radius: 50%; text-align: center; font-size: 13pt; font-weight: 700; color: #333; margin-left: 3mm; vertical-align: 1mm; }
.ts-wohnung { font-size: 12pt; color: #222; margin-bottom: 0.4mm; }
.ts-wohnung-lage { font-size: 10pt; color: #555; margin-bottom: 0; }
.ts-zeitraum { font-size: 11pt; margin-top: 2mm; color: #111; }
.ts-tag { background: transparent !important; color: #777 !important; font-size: 9pt; font-weight: 600; text-transform: uppercase; letter-spacing: 0.2pt; padding: 0; margin-right: 1.5mm; border: 0; display: inline-block; }
.ts-kontakt-grid { margin-top: 2mm; font-size: 10.5pt; color: #222; line-height: 1.45; }
.ts-kontakt-grid .ts-tag { width: 12mm; }
.ts-qr { width: 26mm; flex-shrink: 0; text-align: center; }
.ts-qr img { width: 26mm; height: 26mm; display: block; }
.ts-history { margin-top: 2.5mm; padding-top: 1.5mm; border-top: 0.3pt solid #ddd; font-size: 9pt; color: #666; display: flex; gap: 8mm; }
.ts-history-cell { flex: 1; min-height: 5mm; font-style: italic; }
.ts-history-period { color: #777; font-size: 8pt; font-style: normal; white-space: nowrap; }
.ts-history-cell .ts-tag { font-style: normal; color: #888; }
.ts-tab { position: absolute; top: 0; right: 0; width: 24mm; height: 74mm; box-sizing: border-box; border-left: 0.4pt solid #999; overflow: visible; }
.ts-tab-name { position: absolute; right: -25mm; top: 36mm; width: 66mm; height: 8mm; transform: rotate(-90deg); transform-origin: 50% 50%; font-size: 14pt; font-weight: 700; line-height: 1; white-space: nowrap; letter-spacing: 0; text-align: center; display: flex; align-items: center; justify-content: center; gap: 3mm; }
.ts-tab-inline-id { box-sizing: border-box; width: 8mm; height: 8mm; border: 1pt solid #333; border-radius: 50%; display: inline-flex; align-items: center; justify-content: center; font-size: 10pt; font-weight: 700; color: #222; flex: 0 0 auto; transform: rotate(90deg); }

html:
{%- set ctx = doc.get_trennstreifen_context() -%}
{%- set tab_name = ctx.hauptmieter or doc.name -%}
{%- set tab_wohnung = ((ctx.wohnung_gebaeudeteil ~ " ") if ctx.wohnung_gebaeudeteil else "") ~ (ctx.wohnung_lage or "") -%}
{%- set tab_label = ((tab_wohnung|trim ~ " - ") if tab_wohnung|trim else "") ~ tab_name -%}
{%- set tab_label_len = tab_label|length -%}
{%- set tab_font_size = 6 if tab_label_len > 54 else 7 if tab_label_len > 48 else 8 if tab_label_len > 42 else 9 if tab_label_len > 36 else 10 if tab_label_len > 30 else 11 if tab_label_len > 24 else 13 -%}
<div class="ts">
  <div class="ts-row">
    <div class="ts-main">
      <div class="ts-name">{{ tab_name }}{% if ctx.wohnung_id %}<span class="ts-wohnung-id">{{ ctx.wohnung_id }}</span>{% endif %}</div>
      <div class="ts-wohnung">
        {{ ctx.wohnung_adresse }}{% if ctx.wohnung_gebaeudeteil %} · {{ ctx.wohnung_gebaeudeteil }}{% endif %}
      </div>
      {%- if ctx.wohnung_lage %}
      <div class="ts-wohnung-lage">{{ ctx.wohnung_lage }}</div>
      {%- endif %}
      <div class="ts-zeitraum">
        <span class="ts-tag">{{ _("Mietzeitraum") }}</span>
        {{ frappe.utils.formatdate(ctx.von) if ctx.von else "" }}
        –
        {{ frappe.utils.formatdate(ctx.bis) if ctx.bis else "" }}
      </div>
      <div class="ts-kontakt-grid">
        {%- if ctx.telefon %}<div><span class="ts-tag">{{ _("Tel.") }}</span>{{ ctx.telefon }}</div>{% endif %}
        {%- if ctx.mobil %}<div><span class="ts-tag">{{ _("Mobil") }}</span>{{ ctx.mobil }}</div>{% endif %}
        {%- if ctx.email %}<div><span class="ts-tag">{{ _("Email") }}</span>{{ ctx.email }}</div>{% endif %}
      </div>
    </div>
    {%- if ctx.qr_data_url %}
    <div class="ts-qr">
      <img src="{{ ctx.qr_data_url }}" alt="QR"/>
    </div>
    {%- endif %}
  </div>
  <div class="ts-history">
    <div class="ts-history-cell"><span class="ts-tag">{{ _("vorher") }}:</span>{{ ctx.vormieter or "" }}{% if ctx.vormieter_zeitraum %} <span class="ts-history-period">({{ ctx.vormieter_zeitraum }})</span>{% endif %}</div>
    <div class="ts-history-cell"><span class="ts-tag">{{ _("nachher") }}:</span>{{ ctx.nachmieter or "" }}</div>
  </div>
  <div class="ts-tab"><div class="ts-tab-name" style="font-size: {{ tab_font_size }}pt;">{{ tab_label }}{% if ctx.wohnung_id %}<span class="ts-tab-inline-id">{{ ctx.wohnung_id }}</span>{% endif %}</div></div>
</div>
